const crypto = require('crypto');
const secret = process.env.N8N_WEBHOOK_SECRET;
const signature = $node["webhook-trigger"].json.headers['x-printhub-signature'];
const body = $node["webhook-trigger"].json.body;

if (!secret || !signature) return { valid: false };

const expected = crypto.createHmac('sha256', secret).update(JSON.stringify(body)).digest('hex');
return { valid: signature === expected };

const imageUrls = $node["webhook-trigger"].json.body.imageUrls || [];
const originalName = $node["webhook-trigger"].json.body.originalName;
const platform = $node["webhook-trigger"].json.body.platform;

const content = [
  {
    "type": "text",
    "text": `Analyse these 3D model images. \nOriginal name from source: ${originalName} \nPlatform: ${platform} \n\nDescribe: what it is, complexity level (simple/medium/complex/very complex), estimated print size category, visual appeal, likely use cases, any quality concerns visible.`
  }
];

imageUrls.slice(0, 3).forEach(url => {
  content.push({
    "type": "image_url",
    "image_url": { "url": url }
  });
});

return {
  model: "claude-opus-4-6",
  messages: [
    {
      "role": "system",
      "content": "You are analysing 3D printable model images for PrintHub Africa, a Nairobi-based 3D printing service. Analyse what the model is, its complexity, likely print time category, and visual appeal. Be specific and technical."
    },
    {
      "role": "user",
      "content": content
    }
  ],
  "max_tokens": 400
};

